import{_ as s,o as l,c as i,O as n}from"./chunks/framework.1e3ff9a3.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"product/scenarios.md","filePath":"product/scenarios.md","lastUpdated":1775707265000}'),r={name:"product/scenarios.md"};function e(c,a,t,p,d,o){return l(),i("div",null,a[0]||(a[0]=[n('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Scenarios</p><h1>应用场景</h1><div class="brand-hero__panel"><span class="brand-pill">Usage Thesis</span><strong>不是让 AI 多说一点，而是让任务真正落地。</strong><p>每个场景都围绕“入口、确认、执行、留痕、治理”这条主链路展开。</p></div><p class="brand-lead"> SmartFlow 不是抽象概念站点，它解决的是 <strong>真实任务如何被 AI 安全调度执行</strong>。 场景越真实，这套平台的边界和价值就越清楚。 </p><div class="brand-chip-list"><span class="brand-chip">企业内部自动化</span><span class="brand-chip">多客户交付</span><span class="brand-chip">个人入口</span><span class="brand-chip">混合执行</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">预约场景演示</a><a class="cta-button" href="./capabilities.html">查看核心能力</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>SMARTFLOW // SCENARIO MAP</span><span>DOC 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__value">enterprise_internal_automation</span></span><span class="matrix-panel__line"><span class="matrix-panel__value">multi_customer_delivery</span></span><span class="matrix-panel__line"><span class="matrix-panel__value">personal_entry</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">local_hybrid</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value">template_ops</span></span></div><div class="matrix-panel__callout">SCENARIOS SHOULD MAP TO REAL REVENUE</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">product</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">local execution</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">01</p><h2>企业内部自动化</h2><ul class="brand-list"><li>已有 Python / 自动化脚本，但使用方式分散</li><li>希望把脚本收成统一入口，而不是每个人手工跑环境</li><li>需要执行可留痕、可确认、可审计</li><li>适合数据整理、批量处理、周期报表、规则型触发任务</li></ul></article><article class="brand-card"><p class="brand-kicker">02</p><h2>多客户交付型平台</h2><ul class="brand-list"><li>一个客户一套隔离环境</li><li>平台方统一管理客户、模板、日志和公告</li><li>同一套底座持续复制到多个客户</li><li>重点是“租户边界清晰 + 平台能治理”，不是把所有客户混在一个后台里</li></ul></article><article class="brand-card"><p class="brand-kicker">03</p><h2>个人开发者与小团队入口</h2><ul class="brand-list"><li>把本地脚本整理成可描述、可调用的能力</li><li>用统一入口展示和运行自己的工具</li><li>用 CLI 把本地脚本接入平台</li><li>既是体验入口，也是后续团队协作的升级入口</li></ul></article></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">04</p><h2>混合执行与本地接入</h2><ul class="brand-list"><li>任务涉及本地文件目录</li><li>依赖内网资源、私有数据源或本地网络环境</li><li>Web 端负责入口、规划、确认和留痕</li><li>本地环境与 CLI / Agent 负责真实执行</li></ul></article><article class="brand-card"><p class="brand-kicker">05</p><h2>平台治理与模板运营</h2><ul class="brand-list"><li>模板分发</li><li>公告投放</li><li>客户与租户治理</li><li>平台审计、版本回滚和运营台账</li></ul></article><article class="brand-card"><p class="brand-kicker">06</p><h2>未来边缘与设备场景</h2><ul class="brand-list"><li>边缘节点上的任务执行</li><li>本地设备能力包管理</li><li>设备动作模板与受控触发</li><li>Web 控制面统一管理不同执行端</li></ul></article></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Boss View 01</p><h2>它到底帮团队省什么事</h2><p>把原本靠人手反复执行的脚本、数据处理和流程，收成一个统一入口。团队不需要再记一堆命令、找一堆脚本、问很多人。</p></article><article class="brand-card"><p class="brand-kicker">Boss View 02</p><h2>它为什么不会失控</h2><p>这套平台强调“权限边界 + 人工确认 + 执行留痕”。重点不是让 AI 自由发挥，而是让自动化真正可控。</p></article><article class="brand-card"><p class="brand-kicker">Boss View 03</p><h2>它为什么值得持续投入</h2><p>价值不只是做一次自动化，而是把零散脚本沉淀成可复用、可扩展、可继续接更多场景的管理底座。</p></article></section><section class="brand-card"><p class="brand-kicker">How To Judge Fit</p><h2>如果你属于下面任一类，SmartFlow 的场景匹配度就很高</h2><div class="brand-link-grid"><a class="brand-link-card" href="./capabilities.html"><span>Capability Fit</span><strong>你已经有脚本，但没有统一治理</strong><p>继续看核心能力，确认多租户、执行闭环和模板治理是否契合。</p></a><a class="brand-link-card" href="./deployment.html"><span>Deployment Fit</span><strong>你担心本地环境、内网或混合执行</strong><p>继续看部署方式，理解平台如何把控制面和执行端拆开治理。</p></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead Fit</span><strong>你想直接拿真实场景来沟通</strong><p>直接提交试用 / 演示线索，比空泛介绍更高效。</p></a><a class="brand-link-card" href="./cli.html"><span>CLI Fit</span><strong>你手里已经有本地脚本，想先低成本接起来</strong><p>直接看 CLI 指引，确认当前的登录、注册、执行和 Agent 骨架是否符合你的落地方式。</p></a></div></section></div>',1)]))}const b=s(r,[["render",e]]);export{m as __pageData,b as default};
